/* eslint-disable @angular-eslint/prefer-inject */
import { Inject, Injectable, Injector, Optional, Type } from '@angular/core';
import {
  TreeTableConfiguration,
  TreeTableConfigurationEntry,
} from '../../models';
import { TREE_TABLE_CONFIGS } from '../../../core/models';

/**
 * Factory service for creating TreeTable configurations dynamically
 */
@Injectable({
  providedIn: 'root',
})
export class TreeTableConfigurationFactory {
  private readonly configRegistry = new Map<
    string,
    Type<TreeTableConfiguration>
  >();

  constructor(
    private readonly injector: Injector,
    @Optional()
    @Inject(TREE_TABLE_CONFIGS)
    configurations: TreeTableConfigurationEntry[][] = [],
  ) {
    const flatConfigs = configurations.flat();
    flatConfigs.forEach(({ entityType, config }) => {
      this.configRegistry.set(entityType, config);
    });
  }

  /**
   * Creates a TreeTable configuration for the specified entityType with the given parameters
   * @param entityType The type of TreeTable to create configuration for
   * @param params Optional parameters to pass to the configuration factory
   * @returns A TreeTable configuration object
   */
  create<T>(
    entityType: string,
    params: Record<string, string | number> = {},
  ): TreeTableConfiguration<T> {
    const factory = this.configRegistry.get(entityType);

    if (!factory) {
      throw new Error(
        `No tree table configuration registered for type '${entityType}'`,
      );
    }

    const config = this.injector.get<TreeTableConfiguration<T>>(factory);
    config.initialize(params);
    return config;
  }
}
